/// Features utilities matching TypeScript Anchor SDK utils.features////// Provides feature flag management with exact compatibility/// to the TypeScript Anchor SDK's utils.features module.library;/// Feature flag management utilities////// Matches TypeScript: utils.features.*class FeaturesUtils {  // Enhanced feature set to match TypeScript implementation  static final Set<String> _availableFeatures = {    'debug-logs',    'seeds',    'resolution',     'defaultImpl',    'allowOptionalNesting',    'useDeclaredProgramId',  };    static final Map<String, bool> _features = <String, bool>{    // Default enabled features matching TypeScript defaults    'seeds': true,    'resolution': true,    'defaultImpl': true,  };  /// Set a feature flag  ///  /// Matches TypeScript: utils.features.set(key: string)  static void set(String key) {    if (!_availableFeatures.contains(key)) {      throw ArgumentError('Invalid feature: $key');    }    _features[key] = true;  }  /// Unset a feature flag  ///  /// Matches TypeScript: utils.features.unset(key: string)  static void unset(String key) {    if (!_availableFeatures.contains(key)) {      throw ArgumentError('Invalid feature: $key');    }    _features[key] = false;  }  /// Check if a feature is enabled  ///  /// Matches TypeScript: utils.features.isSet(key: string)  static bool isSet(String key) {    return _features[key] ?? false;  }  /// Get all enabled features  ///  /// Matches TypeScript: utils.features.getEnabled()  static List<String> getEnabled() {    return _features.entries        .where((entry) => entry.value)        .map((entry) => entry.key)        .toList();  }  /// Get all available features  ///  /// Returns list of all features that can be enabled/disabled  static List<String> getAvailable() {    return _availableFeatures.toList();  }  /// Reset all features to default state  ///  /// Clears custom feature flags and restores defaults  static void reset() {    _features.clear();    _features.addAll({      'seeds': true,      'resolution': true,      'defaultImpl': true,    });  }  /// Check if the runtime supports seeds  ///  /// Matches TypeScript: utils.features.isSeeds()  static bool isSeeds() {    return isSet('seeds');  }  /// Check if the runtime supports resolution  ///  /// Matches TypeScript: utils.features.isResolution()  static bool isResolution() {    return isSet('resolution');  }  /// Check if the runtime supports default implementations  ///  /// Matches TypeScript: utils.features.isDefaultImpl()  static bool isDefaultImpl() {    return isSet('defaultImpl');  }  /// Validate feature requirements  ///  /// Ensures required features are available for operation  static bool validateRequiredFeatures(List<String> requiredFeatures) {    return requiredFeatures.every((feature) => isSet(feature));  }  /// Get feature compatibility information  ///  /// Returns compatibility details for debugging  static Map<String, dynamic> getCompatibilityInfo() {    return {      'version': '0.30.0',      'availableFeatures': getAvailable(),      'enabledFeatures': getEnabled(),      'defaultFeatures': ['seeds', 'resolution', 'defaultImpl'],    };  }}
